// Sample input list. In production this comes from a webhook, a CRM, or a Google Sheet.
// Each lead just needs an email; everything else gets enriched below.
return [
  { json: { email: 'priya@hdfcbank.com',   name: 'Priya Sharma' } },
  { json: { email: 'raj@techstartup.io',    name: 'Raj Mehta' } },
  { json: { email: 'someone@gmail.com',      name: 'Anon User' } },
  { json: { email: 'director@cityhospital.org', name: 'Dr. Nair' } }
];

// Enrichment step. Runs on a built-in sample lookup so it works out of the box.
// To go live, swap this for an Apollo/Clay HTTP node and/or a DNS MX lookup - the output shape stays identical.
// Returns company info + which email/collaboration provider the domain runs on.
const FREE = ['gmail.com','yahoo.com','hotmail.com','outlook.com','icloud.com'];
const DB = {
  'hdfcbank.com':     { company: 'HDFC Bank',     industry: 'banking',    employees: 120000, provider: 'Microsoft 365' },
  'techstartup.io':   { company: 'Tech Startup',  industry: 'software',   employees: 40,     provider: 'Google Workspace' },
  'cityhospital.org': { company: 'City Hospital',  industry: 'healthcare', employees: 3000,   provider: 'Legacy Exchange' }
};
const out = [];
for (const item of $input.all()) {
  const email = (item.json.email || '').toLowerCase();
  const domain = email.split('@')[1] || '';
  const isFree = FREE.includes(domain);
  const info = DB[domain] || { company: domain.split('.')[0] || 'Unknown', industry: 'unknown', employees: 0, provider: isFree ? 'Personal email' : 'Unknown' };
  out.push({ json: { ...item.json, domain, is_free_email: isFree, ...info } });
}
return out;

// ============ EDIT THIS: your qualification rules ============
const TARGET_INDUSTRIES = ['banking','healthcare','insurance','government','education','manufacturing'];
const MIN_EMPLOYEES     = 500;
// A lead is a 'switch target' if they already run a rival provider we can displace:
const DISPLACE_PROVIDERS = ['Microsoft 365','Google Workspace','Legacy Exchange'];
// =============================================================

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  let score = 0; const reasons = [];
  if (j.is_free_email) { reasons.push('personal email - disqualify'); out.push({ json: { ...j, fit_score: 0, qualified: false, reasons: reasons.join('; ') } }); continue; }
  if (TARGET_INDUSTRIES.includes(j.industry)) { score += 4; reasons.push('target industry: ' + j.industry); }
  if (j.employees >= MIN_EMPLOYEES) { score += 4; reasons.push(j.employees + ' employees (large seat count)'); }
  else if (j.employees > 0) { reasons.push('too small (' + j.employees + ' emp)'); }
  const switchTarget = DISPLACE_PROVIDERS.includes(j.provider);
  if (switchTarget) { score += 2; reasons.push('switch target: currently on ' + j.provider); }
  const qualified = score >= 6;
  out.push({ json: { ...j, fit_score: score, qualified, switch_target: switchTarget, reasons: reasons.join('; ') } });
}
return out;
